package org.apache.commons.csv;

import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

public class CSVFormatTest {

    @Test
    public void testIsCommentMarkerSet() {
        // Given
        CSVFormat csvFormat = new CSVFormat(',', '"', null, '#', '\\', false, true, "\r\n",
                "\\N", new Object[]{"Header"}, new String[]{"Name", "Age"}, false, false, false, true, false);

        // When
        boolean commentMarkerSet = csvFormat.isCommentMarkerSet();

        // Then
        assertTrue(commentMarkerSet);
    }
}
